const item = $input.first();
const payload = (item.json && item.json.body) || item.json || {};

const to = (payload.to || '').toString().trim();
const subject = (payload.subject || '').toString().trim();
const emailBody = (payload.body || '').toString();
const candidateName = (payload.candidateName || '').toString().trim();
const batchId = (payload.batchId || '').toString().trim();
const fileName = (payload.fileName || '').toString().trim();

const emailPattern = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

const errors = [];
if (!to) errors.push('Missing recipient email');
else if (!emailPattern.test(to)) errors.push('Recipient email looks invalid');
if (!subject) errors.push('Missing subject');
if (!emailBody.trim()) errors.push('Missing email body');

return [{
  json: {
    isValid: errors.length === 0,
    validationError: errors.join('; '),
    to,
    subject,
    body: emailBody,
    candidateName,
    batchId,
    fileName
  }
}];

const item = $input.first();
const validated = $('Validate Payload').first().json;
const message = (item.json && item.json.error && item.json.error.message) || 'Failed to send email via Gmail.';

return [{
  json: {
    to: validated.to,
    error: message
  }
}];
